using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator;

    public PriceCalculatorTests()
    {
        _calculator = new PriceCalculator();
    }

    // --- CalculateTotal: DataRow tests ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.10, 0.00, DisplayName = "Zero unit price")]
    [DataRow(10.00, 0, 0.10, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: DynamicData with ValueTuples for edge cases ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotalEdgeCases))]
    public void CalculateTotal_EdgeCases_ReturnsExpectedTotal(
        decimal unitPrice, int quantity, decimal taxRate, decimal expected)
    {
        var result = _calculator.CalculateTotal(unitPrice, quantity, taxRate);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, decimal expected)> CalculateTotalEdgeCases =>
    [
        (0.01m, 1, 0m, 0.01m),
        (9999.99m, 100, 0.25m, 1249998.75m),
        (1m, 1, 0m, 1m),
    ];

    // --- CalculateTotal: exception tests ---

    [TestMethod]
    public void CalculateTotal_NegativeQuantity_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, -1, 0.1m));

        Assert.AreEqual("quantity", ex.ParamName);
    }

    [TestMethod]
    public void CalculateTotal_NegativeUnitPrice_ThrowsArgumentOutOfRange()
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(-5m, 1, 0.1m));

        Assert.AreEqual("unitPrice", ex.ParamName);
    }

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Tax rate below zero")]
    [DataRow(1.01, DisplayName = "Tax rate above 1")]
    public void CalculateTotal_InvalidTaxRate_ThrowsArgumentOutOfRange(double taxRate)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(10m, 1, (decimal)taxRate));

        Assert.AreEqual("taxRate", ex.ParamName);
    }

    // --- ApplyDiscount: DataRow tests ---

    [TestMethod]
    [DataRow(100.00, 10.0, 90.00, DisplayName = "10% discount")]
    [DataRow(100.00, 0.0, 100.00, DisplayName = "No discount")]
    [DataRow(100.00, 100.0, 0.00, DisplayName = "Full discount")]
    [DataRow(200.00, 25.0, 150.00, DisplayName = "25% off $200")]
    [DataRow(49.99, 50.0, 24.995, DisplayName = "50% off fractional price")]
    public void ApplyDiscount_WithValidInputs_ReturnsDiscountedPrice(
        double price, double discountPercent, double expected)
    {
        var result = _calculator.ApplyDiscount((decimal)price, (decimal)discountPercent);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples ---

    [TestMethod]
    [DynamicData(nameof(DiscountEdgeCases))]
    public void ApplyDiscount_EdgeCases_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountEdgeCases =>
    [
        (0m, 50m, 0m),
        (1000m, 0.5m, 995m),
        (0.01m, 10m, 0.009m),
    ];

    // --- ApplyDiscount: exception tests ---

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Negative discount")]
    [DataRow(100.01, DisplayName = "Discount over 100%")]
    public void ApplyDiscount_InvalidDiscount_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice: DataRow tests ---

    [TestMethod]
    [DataRow(19.99, "$", "$19.99", DisplayName = "Default dollar")]
    [DataRow(19.99, "€", "€19.99", DisplayName = "Euro symbol")]
    [DataRow(0.00, "$", "$0.00", DisplayName = "Zero price")]
    [DataRow(1234.5, "$", "$1234.50", DisplayName = "Pads to two decimals")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

